import base64
import json
import logging
import hashlib
import hmac
import os
from datetime import datetime, timezone

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Shared secret for HMAC verification (store in Secret Manager in production)
HMAC_SECRET = os.environ.get("HMAC_SECRET", "").encode("utf-8")

ALLOWED_JOB_TYPES = frozenset({
    "data_transform",
    "aggregation",
    "report_generation",
    "cleanup",
    "notification",
})

MAX_PAYLOAD_SIZE = 1_048_576  # 1 MB


def verify_message_integrity(payload_bytes: bytes, signature: str) -> bool:
    """Verify HMAC-SHA256 signature of the message payload."""
    if not HMAC_SECRET:
        logger.warning("HMAC_SECRET not configured; skipping integrity check")
        return True
    expected = hmac.new(HMAC_SECRET, payload_bytes, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected, signature)


def validate_job(job: dict) -> bool:
    """Validate that a job dictionary has required fields and safe values."""
    required_fields = {"job_id", "job_type", "payload", "timestamp"}
    if not isinstance(job, dict):
        logger.error("Job is not a dictionary")
        return False
    if not required_fields.issubset(job.keys()):
        missing = required_fields - job.keys()
        logger.error("Job missing required fields: %s", missing)
        return False
    if job["job_type"] not in ALLOWED_JOB_TYPES:
        logger.error("Disallowed job_type: %s", job["job_type"])
        return False
    if not isinstance(job["job_id"], str) or len(job["job_id"]) > 256:
        logger.error("Invalid job_id")
        return False
    return True


def process_job(job: dict) -> dict:
    """Process a validated job based on its type."""
    job_type = job["job_type"]
    job_id = job["job_id"]
    payload = job["payload"]

    logger.info("Processing job %s of type %s", job_id, job_type)

    result = {"job_id": job_id, "status": "completed", "processed_at": datetime.now(timezone.utc).isoformat()}

    if job_type == "data_transform":
        result["output"] = _handle_data_transform(payload)
    elif job_type == "aggregation":
        result["output"] = _handle_aggregation(payload)
    elif job_type == "report_generation":
        result["output"] = _handle_report_generation(payload)
    elif job_type == "cleanup":
        result["output"] = _handle_cleanup(payload)
    elif job_type == "notification":
        result["output"] = _handle_notification(payload)

    return result


def _handle_data_transform(payload: dict) -> dict:
    logger.info("Transforming data: %s records", payload.get("record_count", "unknown"))
    return {"transformed": True, "records_processed": payload.get("record_count", 0)}


def _handle_aggregation(payload: dict) -> dict:
    logger.info("Running aggregation on dataset: %s", payload.get("dataset_id", "unknown"))
    return {"aggregated": True}


def _handle_report_generation(payload: dict) -> dict:
    logger.info("Generating report: %s", payload.get("report_name", "unknown"))
    return {"report_generated": True}


def _handle_cleanup(payload: dict) -> dict:
    logger.info("Running cleanup for scope: %s", payload.get("scope", "unknown"))
    return {"cleaned": True}


def _handle_notification(payload: dict) -> dict:
    logger.info("Sending notification: %s", payload.get("notification_type", "unknown"))
    return {"notified": True}


def process_pubsub(event, context):
    """
    Cloud Function entry point triggered by Pub/Sub.

    SECURITY NOTE: This function uses JSON deserialization instead of pickle.
    Never use pickle.loads() on untrusted data — it allows arbitrary code execution.

    Messages should be JSON-serialized. For complex data structures, use JSON
    with a well-defined schema, Protocol Buffers, or MessagePack.
    """
    logger.info("Function triggered by message ID: %s", context.event_id)

    if "data" not in event:
        logger.error("No data field in Pub/Sub message")
        return

    try:
        raw_data = base64.b64decode(event["data"])
    except Exception:
        logger.error("Failed to base64-decode message data")
        return

    # Check payload size
    if len(raw_data) > MAX_PAYLOAD_SIZE:
        logger.error("Payload exceeds maximum size of %d bytes", MAX_PAYLOAD_SIZE)
        return

    # Verify HMAC signature if present in message attributes
    attributes = event.get("attributes", {}) or {}
    signature = attributes.get("hmac_signature", "")
    if HMAC_SECRET and not verify_message_integrity(raw_data, signature):
        logger.error("Message integrity check failed; rejecting message")
        return

    # Deserialize using JSON (SAFE — unlike pickle)
    try:
        message_data = json.loads(raw_data.decode("utf-8"))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        logger.error("Failed to deserialize message as JSON: %s", e)
        return

    # Handle batch (list of jobs) or single job
    if isinstance(message_data, list):
        jobs = message_data
    elif isinstance(message_data, dict):
        jobs = [message_data]
    else:
        logger.error("Unexpected message format: %s", type(message_data).__name__)
        return

    results = []
    for i, job in enumerate(jobs):
        try:
            if not validate_job(job):
                logger.warning("Skipping invalid job at index %d", i)
                continue
            result = process_job(job)
            results.append(result)
            logger.info("Job %s completed successfully", job.get("job_id", "unknown"))
        except Exception as e:
            logger.exception("Error processing job at index %d: %s", i, e)
            results.append({
                "job_id": job.get("job_id", "unknown"),
                "status": "failed",
                "error": str(e),
            })

    logger.info(
        "Batch processing complete: %d/%d jobs succeeded",
        sum(1 for r in results if r.get("status") == "completed"),
        len(jobs),
    )

    return results


# --- Helper for publishers to create signed messages ---
def create_signed_message(job_data: dict) -> tuple:
    """
    Utility for message publishers to create a properly formatted,
    signed message for the Pub/Sub topic.

    Returns (data_bytes, attributes_dict) for publishing.
    """
    payload = json.dumps(job_data, default=str).encode("utf-8")
    attributes = {}
    if HMAC_SECRET:
        signature = hmac.new(HMAC_SECRET, payload, hashlib.sha256).hexdigest()
        attributes["hmac_signature"] = signature
    return payload, attributes